+    fn strip_ansi(input: &[u8]) -> String {
+        let mut out = Vec::with_capacity(input.len());
+        let mut i = 0;
+        while i < input.len() {
+            if input[i] == 0x1b {
+                if i + 1 >= input.len() {
+                    break;
+                }
+                let next = input[i + 1];
+                if next == b'[' {
+                    i += 2;
+                    while i < input.len() {
+                        let byte = input[i];
+                        i += 1;
+                        if (0x40..=0x7e).contains(&byte) {
+                            break;
+                        }
+                    }
+                    continue;
+                }
+                if next == b']' {
+                    i += 2;
+                    while i < input.len() {
+                        if input[i] == 0x07 {
+                            i += 1;
+                            break;
+                        }
+                        if input[i] == 0x1b && i + 1 < input.len() && input[i + 1] == b'\\' {
+                            i += 2;
+                            break;
+                        }
+                        i += 1;
+                    }
+                    continue;
+                }
+                i += 2;
+                continue;
+            }
+            out.push(input[i]);
+            i += 1;
+        }
+        String::from_utf8_lossy(&out).to_string()
+    }
+
